class Solution:
    def minimumDistance(self, points: List[List[int]]) -> int:
        n = len(points)
        if n == 3:
            # Only 3 points, removing one leaves 2 points, distance is 0
            return 0

        max_dist = float('inf')

        # For each point, compute the max Manhattan distance between any two other points
        for i in range(n):
            current_max = 0
            x1, y1 = points[i]
            for j in range(n):
                if j == i:
                    continue
                x2, y2 = points[j]
                dist = abs(x1 - x2) + abs(y1 - y2)
                current_max = max(current_max, dist)
            max_dist = min(max_dist, current_max)

        return max_dist
